import 'dotenv/config'
import { describe, it, expect, beforeAll, afterAll } from 'vitest'
import supertest from 'supertest'
import { buildApp } from '../app'
import { prisma } from '../lib/prisma'
import { redis } from '../plugins/redis'
import * as bcrypt from 'bcrypt'

const app = buildApp()

describe('CRUD Linków', () => {
  let marketerToken: string
  let clientToken: string
  let marketerId: string
  let linkId: string

  beforeAll(async () => {
    await app.ready()
    const passwordHash = await bcrypt.hash('test1234', 10)
    
    const marketer = await prisma.user.create({
      data: { email: 'links-marketer@test.com', passwordHash, role: 'marketer' }
    })
    marketerId = marketer.id
    
    const client = await prisma.user.create({
      data: { email: 'links-client@test.com', passwordHash, role: 'client' }
    })

    marketerToken = app.jwt.sign({ sub: marketer.id, role: marketer.role })
    clientToken = app.jwt.sign({ sub: client.id, role: client.role })
  })

  afterAll(async () => {
    await prisma.link.deleteMany()
    await prisma.user.deleteMany()
    await redis.quit()
    await app.close()
    await prisma.$disconnect()
  })

  it('POST /api/links - pozwala marketerowi stworzyć link', async () => {
    const response = await supertest(app.server)
      .post('/api/links')
      .set('Authorization', `Bearer ${marketerToken}`)
      .send({ original_url: 'https://jestesmy-super.pl', campaign_name: 'Test' })

    expect(response.status).toBe(201)
    expect(response.body).toHaveProperty('id')
    expect(response.body).toHaveProperty('short_code')
    expect(response.body.short_code.length).toBe(6)
    
    linkId = response.body.id
  })

  it('POST /api/links - blokuje klienta (role client)', async () => {
    const response = await supertest(app.server)
      .post('/api/links')
      .set('Authorization', `Bearer ${clientToken}`)
      .send({ original_url: 'https://jestesmy-super.pl' })

    expect(response.status).toBe(403)
  })

  it('GET /api/links - pobiera zpaginowaną listę linków dla marketera', async () => {
    const response = await supertest(app.server)
      .get('/api/links?page=1&limit=10')
      .set('Authorization', `Bearer ${marketerToken}`)

    expect(response.status).toBe(200)
    expect(response.body.data).toBeInstanceOf(Array)
    expect(response.body.total).toBeGreaterThanOrEqual(1)
  })

  it('PATCH /api/links/:id - pozwala aktualizować link (np. is_active)', async () => {
    const response = await supertest(app.server)
      .patch(`/api/links/${linkId}`)
      .set('Authorization', `Bearer ${marketerToken}`)
      .send({ is_active: false })

    expect(response.status).toBe(200)
    expect(response.body.isActive).toBe(false)
  })

  it('DELETE /api/links/:id - wykonuje soft delete', async () => {
    const response = await supertest(app.server)
      .delete(`/api/links/${linkId}`)
      .set('Authorization', `Bearer ${marketerToken}`)

    expect(response.status).toBe(204)

    // Weryfikacja soft delete
    const inDb = await prisma.link.findUnique({ where: { id: linkId } })
    expect(inDb?.deletedAt).not.toBeNull()
  })
})
